css:
.loader {
  display: grid;
  gap: 10px;
  width: 148px;
  border-radius: 18px;
  padding: 14px;
  background: rgba(99, 102, 241, 0.08);
}
.loader b,
.loader i {
  display: block;
  border-radius: 12px;
  background: linear-gradient(90deg, rgba(99,102,241,.14), rgba(99,102,241,.34), rgba(99,102,241,.14));
  background-size: 220% 100%;
  animation: shimmer 1.15s linear infinite;
}
.loader b { height: 44px; }
.loader i { height: 10px; }
.loader i:last-child { width: 66%; }
@keyframes shimmer { to { background-position: -220% 0; } }
